<template>
  <div
    v-show="showTab"
    class="fixed top-16 w-full z-50"
    ref="webTab"
    :style="{
      transform: `translate(${ismove ? curOffsetX : offSetX}px, ${
        ismove ? curOffsetY : offSetY
      }px)`,
    }"
    @click.stop
  >
    <div
      class="max-w-7xl relative mx-auto px-4 py-3 bg-white border-2 shadow-xl flex flex-col"
      style="height: 40rem"
    >
      <div
        class="flex w-full py-6 border-b-2 shadow-sm justify-between items-center cursor-pointer"
        @mousedown="dragTabStart"
        @mouseup="dragTabEnd"
        @touchstart="dragTabStart"
        @tounchend="dragTabEnd"
      >
        <!-- 左侧菜单栏 -->
        <div class="text-white text-opacity-0 hover:text-opacity-100">
          <div class="flex">
            <div
              @click="hide"
              class="bg-red-600 cursor-pointer rounded-full h-4 w-4 mx-1 flex items-center justify-center"
            >
              x
            </div>
            <div
              class="bg-yellow-600 cursor-pointer rounded-full h-4 w-4 mx-1 flex items-center justify-center"
            >
              -
            </div>
            <div
              @click="show"
              class="bg-green-600 cursor-pointer rounded-full h-4 w-4 mx-1 flex items-center justify-center"
            >
              Ο
            </div>
          </div>
        </div>
        <div class="text-right">
          <button @click.stop="open(tabSrc)">去官网打开</button>
        </div>
      </div>
      <div id="ComTabPanel" class="w-full flex-grow">
        <div>{{ message }}</div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: "ComTab",
  data() {
    return {
      showTab: false,
      ismove: false,
      tabSrc: "",
      message: "",
      offSetX: 0,
      offSetY: 0,
      curOffsetX: 0,
      curOffsetY: 0,
      entryX: 0,
      entryY: 0,
    };
  },
  computed: {
    frame() {
      //  <iframe :src="tabSrc" style="height: 100%; width: 100%"></iframe>
      let frame = document.createElement("iframe");
      frame.setAttribute("style", "height: 100%; width: 100%");
      return frame;
    },
  },
  methods: {
    open(url) {
      window.open(url);
    },
    goto(url) {
      this.tabSrc = url;
      // this.message = "loading"
      let _this = this;

      let frame = this.frame;
      frame.setAttribute("src", url);
      document.querySelector("#ComTabPanel").appendChild(frame);

      // 等待3秒，判断iframe是否加载成功
      // setTimeout(() => {
      //   console.log(_this.frame.innerText.search("拒绝了我们的连接请求"))
      //   if (_this.frame.innerText.search("拒绝了我们的连接请求") != -1) {
      //     document.querySelector("#ComTabPanel").removeChild(this.frame);
      //     _this.message = "连接失败，建议去官网打开";
      //   } else {
      //     _this.message = "";
      //   }
      // }, 3000);
    },
    show() {
      this.showTab = true;
    },
    hide() {
      this.$store.dispatch("CloseTab");
      this.showTab = false;
      this.frame.removeAttribute("src");
      try {
        document.querySelector("#ComTabPanel").removeChild(this.frame);
      } catch (error) {
        // console.log(error);
      }
    },
    dragTabStart(event) {
      this.entryX = event.clientX;
      this.entryY = event.clientY;
      this.$refs.webTab.addEventListener("mousemove", this.dragTab, false);
      this.$refs.webTab.addEventListener("tounchmove", this.dragTab, false);
      this.curOffsetX = this.offSetX;
      this.curOffsetY = this.offSetY;
      this.ismove = true;
    },
    dragTab(event) {
      if (this.ismove) {
        this.curOffsetX = this.offSetX + event.clientX - this.entryX;
        this.curOffsetY = this.offSetY + event.clientY - this.entryY;
      }
    },
    dragTabEnd(event) {
      this.offSetX = this.curOffsetX;
      this.offSetY = this.curOffsetY;
      this.ismove = false;

      this.curOffsetX = 0;
      this.curOffsetY = 0;
      this.$refs.webTab.removeEventListener("mousemove", this.dragTab);
      this.$refs.webTab.removeEventListener("tounchmove", this.dragTab);
    },
  },
};
</script>