<template>
  <div
    :class="[
      showSearch
        ? 'animate__animated animate__delay-0.5s animate__fadeIn animate__bounceIn'
        : 'hidden',
    ]"
    class="fixed top-1/3 w-full z-100"
    style="height: 6rem"
    @click.stop
  >
    <div class="mx-auto max-w-4xl px-3 py-4">
      <div
        @mousedown="move"
        @mouseup="stop"
        class="relative bg-white w-full h-3/4 overflow-hidden overflow-scroll-none shadow-xl rounded-xl"
      >
        <div
          ref="scrollBg"
          class="w-full h-full flex flex-nowrap cursor-pointer items-center justify-start text-center"
          :style="{
            transform: 'translateX(' + (isMove ? transLateX : offSet) + 'px)',
          }"
        >
          <div class="w-1/3 flex-none py-3">
            <router-link
              tag="div"
              to="/"
              class="w-1/4 mx-auto bg-pink-400 py-4 rounded-full hover:bg-pink-600"
            >
              <font-awesome-icon
                icon="compass"
                class="fa-2x fill-current text-white"
              />
            </router-link>
          </div>
          <div class="w-1/3 flex-none py-3">
            <router-link
              tag="div"
              to="/blog"
              class="w-1/4 mx-auto bg-pink-400 py-4 rounded-full hover:bg-pink-600"
            >
              <font-awesome-icon
                icon="book"
                class="fa-2x fill-current text-white"
              />
            </router-link>
          </div>
          <div class="w-1/3 flex-none py-3">
            <router-link
              tag="div"
              to="/game"
              class="w-1/4 mx-auto bg-pink-400 py-4 rounded-full hover:bg-pink-600"
            >
              <font-awesome-icon
                icon="gamepad"
                class="fa-2x fill-current text-white"
              />
            </router-link>
          </div>
          <div class="w-1/3 flex-none py-3">
            <router-link
              tag="div"
              to="/user"
              class="w-1/4 mx-auto bg-pink-400 py-4 rounded-full hover:bg-pink-600"
            >
              <font-awesome-icon
                icon="user-astronaut"
                class="fa-2x fill-current text-white"
              />
            </router-link>
          </div>
          <div class="w-1/3 flex-none py-3">
            <router-link
              tag="div"
              class="w-1/4 mx-auto bg-pink-400 py-4 rounded-full hover:bg-pink-600"
              to="/comming"
            >
              <font-awesome-icon
                icon="ellipsis-h"
                class="fa-2x fill-current text-white"
              />
            </router-link>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: "ComSearch",
  data() {
    return {
      offSet: 0, // 当前的偏移量
      transLateX: 0,
      entryX: 0, // 点击事件发生时x左边
      curX: 0, // 移动过程中x左边
      isMove: false,
      maxoff: 0, // 能移动的最大值
      showSearch: false,
    };
  },
  computed: {
    minOff() {
      return this.$refs.scrollBg.clientWidth - this.$refs.scrollBg.scrollWidth;
    },
    maskDom() {
      let mask = document.createElement("div");
      mask.setAttribute(
        "class",
        "fixed w-screen h-screen inset-0 bg-black opacity-50 z-99"
      );
      return mask;
    },
    searchStatus() {
      return this.$store.getters.searchTab;
    },
  },
  watch: {
    searchStatus() {
      if (this.searchStatus === true) {
        this.show();
      } else {
        this.hide();
      }
    },
  },
  methods: {
    _hide() {
      this.$store.dispatch("CloseSearch");
    },
    show() {
      document.body.appendChild(this.maskDom);
      document.addEventListener("click", this._hide, false);
      this.showSearch = true;
    },
    hide() {
      document.body.removeChild(this.maskDom);
      document.removeEventListener("click", this._hide);
      this.showSearch = false;
    },
    toggle() {
      if (this.showSearch) {
        this.hide();
      } else {
        this.show();
      }
    },
    move(event) {
      // mousewheel是滚轮，这里需要实现的是先点击，然后绑定，move事件，让位置跟随鼠标移动
      if (event.button == 0) {
        //判断是否点击鼠标左键
        this.entryX = event.clientX;
        this.transLateX = this.offSet;
        this.isMove = true;
        this.$refs.scrollBg.addEventListener(
          "mousemove",
          this.scrollMove,
          false
        );
      }
      return false; //阻止默认事件或冒泡
    },
    stop(event) {
      if (event.button == 0) {
        this.offSet = this.transLateX;
        this.isMove = false;
        this.$refs.scrollBg.removeEventListener("mousemove", this.scrollMove);
      }
    },
    scrollMove(event) {
      if (
        this.offSet + event.clientX - this.entryX >= this.minOff &&
        this.offSet + event.clientX - this.entryX <= this.maxoff
      ) {
        // 超过边界就无法移动
        this.transLateX = this.offSet + event.clientX - this.entryX;
      }
    },
  },
};
</script>