<template>
  <div id="app">
    <div id="tookit">
      <com-search ref="search" />
      <com-tab ref="hometab" />
      <com-contact />
    </div>
    <transition :name="transitionName">
      <!-- <router-view /> -->
      <router-view></router-view>
    </transition>
    <!-- <div id="layout">
      <menu-page v-show="page == 'menu'" />
      <blog-page v-show="page == 'blog'" />
      <user-page v-show="page == 'user'" />
      <coming-page v-show="page == 'coming'" />
    </div> -->
  </div>
</template>

<script>
import ComTab from "./components/Tab.vue";
import ComContact from "./components/Contact.vue";
import ComSearch from "./components/Search.vue";
// import MenuPage from "./components/menu/Main.vue";
// import BlogPage from "./components/blog/Main.vue";
// import UserPage from "./components/user/Main.vue";
// import ComingPage from "./components/coming/Main.vue";

export default {
  name: "App",
  components: {
    ComTab,
    ComContact,
    ComSearch,
    // MenuPage,
    // BlogPage,
    // UserPage,
    // ComingPage,
  },
  data() {
    return {
      page: "menu",
      actions: [], // Shift + C // 跳出搜索框
      transitionName: "",
    };
  },
  computed: {
    tabOpen() {
      return this.$store.getters.tabOpen;
    },
    tabUrl() {
      return this.$store.getters.tabUrl;
    },
  },
  watch: {
    $route(to, from) {
      console.log(to, from);
      this.transitionName = "fold-left";
    },
    tabOpen() {
      if (this.tabOpen) {
        this.$refs.hometab.show();
        document.addEventListener("click", this.event_close, false);
      } else {
        // document.removeEventListener("click", this.event_close);
      }
    },
    tabUrl() {
      if (this.tabOpen) {
        this.$refs.hometab.goto(this.tabUrl);
      }
    },
  },
  created() {
    var _this = this;

    // 监听按钮事件
    document.onkeydown = function (e) {
      _this.actions.push(e.key.toLowerCase());
      _this.try_action();
    };
  },
  mounted() {
    this.$refs.hometab.hide();
  },
  methods: {
    try_action() {
      if (this.actions[this.actions.length - 1] === "l") {
        this.$store.dispatch("OpenSearch");
      }
    },
    event_close() {
      this.$refs.hometab.hide();
    },
  },
};
</script>

<style>
.fold-left-enter-active {
  animation-name: fold-left-in;
  animation-duration: 0.3s;
}
.fold-left-leave-active {
  animation-name: fold-left-out;
  animation-duration: 0.3s;
}
.fold-right-enter-active {
  animation-name: fold-right-in;
  animation-duration: 0.3s;
}
.fold-right-leave-active {
  animation-name: fold-right-out;
  animation-duration: 0.3s;
}

@keyframes fold-left-in {
  0% {
    transform: translate3d(100%, 0, 0);
  }
  100% {
    transform: translate3d(0, 0, 0);
  }
}
@keyframes fold-left-out {
  0% {
    transform: translate3d(0, 0, 0);
  }
  100% {
    transform: translate3d(-100%, 0, 0);
  }
}
</style>
