import Vue from 'vue'
import Vuex from 'vuex'

Vue.use(Vuex)

export default new Vuex.Store({
    state: {
        tabOpen: false, // tab窗口的状态
        tabUrl: "", // tab浏览器的url地址
        searchTab: false, // search的状态
    },
    getters: {
        tabOpen: state => state.tabOpen,
        tabUrl: state => state.tabUrl,
        searchTab: state => state.searchTab,
    },
    mutations: {
        OpenTab(state, url) {
            state.tabOpen = true
            state.tabUrl = url
        },
        CloseTab(state) {
            state.tabOpen = false
            state.tabUrl = ""
        },
        OpenSearch(state) {
            state.searchTab = true
        },
        CloseSearch(state) {
            state.searchTab = false
        }
    },
    actions: {
        OpenTab(ctx, url) {
            ctx.commit("OpenTab", url)
        },
        CloseTab(ctx) {
            ctx.commit("CloseTab")
        },
        OpenSearch(ctx) {
            ctx.commit("OpenSearch")
        },
        CloseSearch(ctx) {
            ctx.commit("CloseSearch")
        }
    }
})